const channels = $input.first().json;
const staticData = $getWorkflowStaticData('global');
if (!staticData.lastIds) staticData.lastIds = {};

// Discord epoch pro výpočet snowflake
const DISCORD_EPOCH = 1420070400000n;
const twelveHoursAgo = BigInt(Date.now() - 12 * 60 * 60 * 1000);
const defaultSnowflake = String((twelveHoursAgo - DISCORD_EPOCH) << 22n);

// Přeskočit tyto kanály (soukromé, admin, archiv, log, nsfw)
const SKIP_NAMES = [
  'moderátoři', 'cbh-moderators', 'testovací-kanál', 'nastavení-botů',
  'log-pristup', 'log-zprávy', 'log', 'fve-soukrome', 'stream-chat-uzavřeno-archivní',
  'midjourney-bot', 'párty_21-05-29', 'bazar-old', 'pikle', 'ymovie-ascc',
  'ebooks-for-vip', 'vlákna🧵📌', 'olé-dezolé', 'kanál-nsfw'
];

// Typ 0 = textový kanál, typ 5 = announcement kanál
// Přeskočit type 2 (hlas), 4 (kategorie), 13 (stage), 15 (forum)
const textChannels = channels
  .filter(ch => (ch.type === 0 || ch.type === 5) && !ch.nsfw)
  .filter(ch => !SKIP_NAMES.includes(ch.name))
  .map(ch => ({
    channelId: ch.id,
    channelName: ch.name,
    after: staticData.lastIds[ch.id] || defaultSnowflake
  }));

return textChannels.map(ch => ({ json: ch }));

const response = $json;
const channelId = $('Filtruj textove kanaly').item.json.channelId;
const channelName = $('Filtruj textove kanaly').item.json.channelName;

// Pokud API vrátilo chybu (403 = nemáme přístup), přeskoč
if (!Array.isArray(response)) {
  return { json: { channelId, channelName, text: '', hasMessages: false, lastId: null } };
}

const messages = response;
if (messages.length === 0) {
  return { json: { channelId, channelName, text: '', hasMessages: false, lastId: null } };
}

// Seřaď chronologicky
const sorted = [...messages].sort((a, b) => {
  const aId = BigInt(a.id);
  const bId = BigInt(b.id);
  return aId < bId ? -1 : aId > bId ? 1 : 0;
});

const lastId = sorted[sorted.length - 1].id;

// Filtruj boty a prázdné zprávy
const text = sorted
  .filter(m => !m.author?.bot && m.content && m.content.trim().length > 0)
  .map(m => {
    const time = new Date(m.timestamp).toLocaleTimeString('cs-CZ', { hour: '2-digit', minute: '2-digit' });
    return `[${time}] ${m.author.username}: ${m.content.trim()}`;
  })
  .join('\n');

// Ulož poslední ID
const staticData = $getWorkflowStaticData('global');
if (!staticData.lastIds) staticData.lastIds = {};
if (lastId) staticData.lastIds[channelId] = lastId;

return { json: { channelId, channelName, text, hasMessages: text.length > 0, lastId } };

const items = $input.all();
const hasAny = items.some(i => i.json.hasMessages);

if (!hasAny) {
  return [{ json: { hasMessages: false, combined: '', timestamp: '' } }];
}

const parts = items
  .filter(i => i.json.hasMessages)
  .map(i => `## #${i.json.channelName}\n${i.json.text}`);

// Limit 20k znaků kvůli nákladům na API
const combined = parts.join('\n\n---\n\n').substring(0, 20000);
const now = new Date().toLocaleString('cs-CZ', { timeZone: 'Europe/Prague' });
const channelCount = items.filter(i => i.json.hasMessages).length;

return [{ json: { hasMessages: true, combined, timestamp: now, channelCount } }];

const content = $json.content || [];
const summaryText = content.find(c => c.type === 'text')?.text || 'Nepodařilo se vygenerovat shrnutí.';
const timestamp = $('Agreguj').first().json.timestamp;
const channelCount = $('Agreguj').first().json.channelCount;

const slackText = `*🤖 IoT CZ Discord Shrnutí — ${timestamp}*\n_Aktivní kanály: ${channelCount}_\n\n${summaryText}`;
const discordText = `**🤖 IoT CZ Discord Shrnutí — ${timestamp}**\n_Aktivní kanály: ${channelCount}_\n\n${summaryText}`.substring(0, 1990);

return [{ json: { summaryText, slackText, discordText, timestamp } }];
